import { Edge } from 'butterfly-dag';
// import { Edge } from '../../../index';
const $ = require('jquery');

class BaseEdge extends Edge {
  draw(obj) {
    let path = super.draw(obj);
    if (this.options.lineType) {
      $(path).addClass(this.options.lineType);
    }
    return path;
  }
  drawArrow(isShow) {
    let dom = super.drawArrow(isShow);
    if (this.options.color) {
      $(dom).addClass(this.options.color);
    }
    return dom;
  }
};
module.exports = BaseEdge;

import React, {Component} from 'react';
import ReactDOM from 'react-dom';

import mockData from './data';
import {Canvas} from 'butterfly-dag';
// import {Canvas} from 'local::butterfly-dag'; // 引用本地数据时使用

import './index.less';
import 'antd/dist/antd.css';
import 'butterfly-dag/dist/index.css';

class DagreGroupLayout extends Component {
  constructor() {
    super();
    this.canvas = null;
  }

  componentDidMount() {
    let root = document.getElementById('dag-canvas');

    this.canvas = new Canvas({
      root: root,
      disLinkable: true, // 可删除连线
      linkable: true,    // 可连线
      draggable: true,   // 可拖动
      zoomable: true,    // 可放大
      moveable: true,    // 可平移
      layout: {
        type: 'dagreGroupLayout',
        options: {
          rankdir: 'TB',
          nodesep: 40,
          ranksep: 50,
          controlPoints: false,
        },
      },
      theme: {
        edge: {
          shapeType: 'AdvancedBezier',
          arrow: true,
          arrowPosition: 0.5
        }
      }
    });
    this.canvas.draw(mockData);
  }

  render() {
    return (
      <div className='dagre-group'>
        <div className="dagre-group-canvas" id="dag-canvas">
        </div>
      </div>
    );
  }
}

ReactDOM.render(<DagreGroupLayout />, document.getElementById('root'));

'use strict';

import $ from 'jquery';
import {Node} from 'butterfly-dag';
// import { Node } from '../../../index';

import './node.less';

class BaseNode extends Node {
  constructor(opts) {
    super(opts);
    this.options = opts;
  }
  draw = (opts) => {
    const container = $('<div class="dagre-group-base-node"></div>')
                    .attr('id', opts.id)
                    .css('top', opts.top + 'px')
                    .css('left', opts.left + 'px')

    this._createTypeIcon(container);
    this._createText(container);

    return container[0];
  }
  _createTypeIcon(dom = this.dom) {
    const iconContainer = $(`<span class="icon-box ${this.options.className}"></span>`)[0];
    const icon = $(`<i class="iconfont ${this.options.iconType}"></i>`)[0];

    iconContainer.append(icon);
    $(dom).append(iconContainer);
  }

  _createText(dom = this.dom) {
    $('<span class="text-box"></span>').text(this.options.label).appendTo(dom);
  }
}

module.exports = BaseNode;

@import 'theme.less'; 
.dagre-group-base-node {
  position: absolute;
  height: 36px;
  width: 116;
  line-height: 36px;
  text-align: center;
  background: @butterfly-theme-color;
  border-radius: @butterfly-box-radius;
  border: @butterfly-box-border;
  box-shadow: @butterfly-box-shadow;
  color: @butterfly-normal-font-color;
  .icon-box {
    display: inline-block;
    height: 30px;
    line-height: 30px;
    width: 30px;
    border-radius: 15px;
    position: relative;
    left: 2px;
    .iconfont {
      color: @butterfly-overlay-font-color;
    }
  }
  .text-box {
    display: inline-block;
    height: 30px;
    width: 86px;
    padding: 0 10px;
    line-height: 30px;
    font-size: 12px;
  }
  .icon-background-color{
    background-color: @butterfly-primary-color;
  }
  .deep-blue {
    background: #597EF7;
  }
}

@butterfly-theme-color-base:#fff;
@butterfly-normal-font-color-base:#222;;
@butterfly-overlay-font-color-base:#FFF;
@butterfly-primary-color-base:#F66902;
@butterfly-box-border-color-base: #D9D9D9;
